noncompliant:
for (int i = 0; i < 10; i--) // Noncompliant: counter moves away from condition
{
    Console.WriteLine(i);
}

for (int i = 10; i > 0; i++) // Noncompliant: counter moves away from condition
{
    Console.WriteLine(i);
}

compliant:
for (int i = 0; i < 10; i++) // Compliant: counter moves toward condition
{
    Console.WriteLine(i);
}

for (int i = 10; i > 0; i--) // Compliant: counter moves toward condition
{
    Console.WriteLine(i);
}
